440	 * Handle a message when specialist proxy is active.
441	 * Returns true if handled (caller should return early), false if not in proxy mode.
442	 */
443	export async function handleSpecialistProxy(opts: ProxyHandlerOpts): Promise<boolean> {
444	  const { chatId, text, ctx, session, streamEditIntervalMs, rateLimitedUntil } = opts;
445	  if (!isProxyActive(chatId)) return false;
446	
447	  const target = getProxyTarget(chatId)!;
448	  try {
449	    const prefix = `🤖 *[${target}]*\n`;
450	    const placeholder = await ctx.reply(`${prefix}Thinking… ▍`, { parse_mode: "Markdown" })
451	      .catch(() => ctx.reply(`🤖 [${target}]\nThinking… ▍`));
452	
453	    let lastEditAt = 0;
454	    let lastRendered = "";
455	    let editTimer: NodeJS.Timeout | null = null;
456	
457	    const editNow = async (content: string) => {
458	      if (rateLimitedUntil > Date.now()) return;
459	      const body = content.length > TG_MAX ? "…" + content.slice(-TG_MAX) : content;
460	      const frame = `${prefix}${body} ▍`;
461	      if (frame === lastRendered) return;
462	      lastRendered = frame;
463	      lastEditAt = Date.now();
464	      try {
465	        await ctx.api.editMessageText(chatId, placeholder.message_id, frame, { parse_mode: "Markdown" });
466	      } catch {
467	        await ctx.api.editMessageText(chatId, placeholder.message_id, `🤖 [${target}]\n${body} ▍`).catch(() => {});
468	      }
469	    };
470	
471	    const onChunk = (currentOutput: string) => {
472	      const stripped = stripMemoryTokens(currentOutput).replace(/<<PROXY_DONE>>/gi, "").trim();
473	      if (!stripped) return;
474	      const elapsed = Date.now() - lastEditAt;
475	      if (elapsed >= streamEditIntervalMs) {
476	        editNow(stripped);
477	      } else if (!editTimer) {
478	        editTimer = setTimeout(() => {
479	          editTimer = null;
480	          const latest = stripMemoryTokens(currentOutput).replace(/<<PROXY_DONE>>/gi, "").trim();
481	          if (latest) editNow(latest);
482	        }, streamEditIntervalMs - elapsed);
483	      }
484	    };
485	
486	    const { output, proxyDone } = await promptProxy(chatId, text, onChunk, ctx.from?.id);
487	    if (editTimer) { clearTimeout(editTimer); editTimer = null; }
488	
489	    extractMemoryTokensFromProxy(output, ctx.from?.id ?? chatId, target);
490	
491	    const proxyTokensRaw = transformReplyTokens(output, {
492	      parseDuration: opts.parseDuration,
493	      parseAbsoluteTime: opts.parseAbsoluteTime,
494	      parseRecurrence: opts.parseRecurrence,
495	      computeNextRunAt: opts.computeNextRunAt,
496	    });
497	    const proxyTokens = filterTransformedByPolicy(proxyTokensRaw, "proxy");
498	
499	    if (proxyTokens.sendFiles.length > 0) {
500	      sendFilesByPaths(ctx, proxyTokens.sendFiles).catch((err) =>
501	        console.error(`[specialist:proxy] sendFilesByPaths failed:`, err));
502	    }
503	
504	    for (const emotion of proxyTokens.stickerEmotions) {
505	      const fileId = STICKER_MAP[emotion];
506	      if (fileId) {
507	        ctx.replyWithSticker(fileId).catch((err) =>
508	          console.warn(`[specialist:proxy] STICKER ${emotion} failed:`, (err as Error).message));
509	      }
510	    }
511	
512	    if (proxyTokens.skillUsages.length > 0) {
513	      const skillDir = detectSkillDir();
514	      if (!skillDir.startsWith("(")) {
515	        for (const u of proxyTokens.skillUsages) {
516	          usageStore.markUsed(skillDir, u.name, u.reason).catch(() => {});
517	        }
518	      }
519	    }
520	
521	    const display = proxyTokens.text.trim();
522	    const proxyStats = getProxyStats(chatId);
523	    const proxyUsage = (() => {
524	      if (!proxyStats) return "";
525	      const inTok = opts.estimateTokens(proxyStats.charsIn);
526	      const outTok = opts.estimateTokens(proxyStats.charsOut);
527	      const totalTok = inTok + outTok;
528	      const limit = config.contextWindowTokens;
529	      const pctStr = limit ? ((totalTok / limit) * 100).toFixed(1) + "%" : "";
530	      return `\n\n— ctx ~${totalTok}/${limit} tok (${pctStr}) • in ${inTok} · out ${outTok}`;
531	    })();
532	
533	    if (display) {
534	      const fullText = `${display}${proxyUsage}`;
535	      const chunks = splitForTelegram(fullText);
536	      const proxyAskKb = buildAskKeyboard(proxyTokens.askTokens);
537	      const first = `${prefix}${chunks[0]}`;
538	      const isLastChunk = chunks.length === 1;
539	      await ctx.api.editMessageText(chatId, placeholder.message_id, first, {
540	        parse_mode: "Markdown",
541	        ...(isLastChunk && proxyAskKb ? { reply_markup: proxyAskKb } : {}),
542	      }).catch(() => ctx.api.editMessageText(chatId, placeholder.message_id, `🤖 [${target}]\n${chunks[0]}`, {
543	        ...(isLastChunk && proxyAskKb ? { reply_markup: proxyAskKb } : {}),
544	      }).catch(() => {}));
545	      if (isLastChunk && proxyAskKb) {
546	        askRegistry.set(placeholder.message_id, proxyTokens.askTokens);
547	      }
548	      for (let ci = 1; ci < chunks.length; ci++) {
549	        const isLast = ci === chunks.length - 1;
550	        const msg = await ctx.api.sendMessage(chatId, chunks[ci], {
551	          parse_mode: "Markdown",
552	          ...(isLast && proxyAskKb ? { reply_markup: proxyAskKb } : {}),
553	        }).catch(() => ctx.api.sendMessage(chatId, chunks[ci]).catch(() => null));
554	        if (isLast && proxyAskKb && msg?.message_id) {
555	          askRegistry.set(msg.message_id, proxyTokens.askTokens);
556	        }
557	      }
558	    } else {
559	      await ctx.api.editMessageText(chatId, placeholder.message_id, `${prefix}(no response)`, { parse_mode: "Markdown" }).catch(() => {});
560	    }
561	
562	    if (proxyDone) {
563	      const proxySession = endProxy(chatId);
564	      await ctx.reply(`✅ Specialist "${target}" 完成，已切回主 agent。`);
565	      if (proxySession) {
566	        const summary = buildProxySummary(proxySession);
567	        const userId = ctx.from?.id ?? chatId;
568	        const { runPrompt, sessions } = deps();
569	        const s = await sessions.get(chatId, userId);
570	        const fakeCtx = {
571	          chat: { id: chatId, type: "private" as const },
572	          from: { id: userId, is_bot: false, first_name: "system" },
573	          message: { message_id: 0, date: 0, chat: { id: chatId, type: "private" as const }, text: summary },
574	          api: ctx.api,
575	          reply: (t: string, extra?: any) => ctx.api.sendMessage(chatId, t, extra),
576	        } as unknown as Context;
577	        runPrompt(fakeCtx, s, summary, { kind: "meta" }).catch(() => {});
578	      }
579	    }
580	  } catch (err) {
581	    console.error(`[specialist:proxy] prompt to "${target}" failed:`, err);
582	    await ctx.reply(`⚠️ Specialist "${target}" 回覆失敗：${(err as Error).message}`);
583	  }
584	  return true;
585	}
